{"code": "import json
import re

# Load full clinical data
clinical_data = locals()['var_functions.query_db:22']
if isinstance(clinical_data, str):
    with open(clinical_data, 'r') as f:
        clinical_data = json.load(f)

# Extract female BRCA patients with known histological types
female_brca_patients = []
patient_hist_type = {}
patient_barcodes = set()

for record in clinical_data:
    patient_desc = record.get('Patient_description', '')
    hist_type = record.get('histological_type', '')

    if hist_type not in ['', 'Other  specify']:
        barcode_match = re.search(r'(TCGA-\w+-\w+)', patient_desc)
        if barcode_match:
            barcode = barcode_match.group(1)
            if barcode not in patient_barcodes:
                patient_barcodes.add(barcode)
                female_brca_patients.append({
                    'ParticipantBarcode': barcode,
                    'histological_type': hist_type
                })
                patient_hist_type[barcode] = hist_type

print('__RESULT__:')
print(json.dumps({
    'total_unique_patients': len(patient_barcodes),
    'sample_patients': list(patient_barcodes)[:5]
}))"}

